func Or(predicates ...predicate.KDSSyncFailure) predicate.KDSSyncFailure {
	return predicate.KDSSyncFailure(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.KDSSyncFailure) predicate.KDSSyncFailure {
	return predicate.KDSSyncFailure(sql.NotPredicates(p))
}
